"use client";
import React from "react";
import Link from "next/link";
import {
  UserCheck,
  LayoutDashboard,
  LogOut,
  ShieldCheck,
  Sparkles,
  ArrowRight,
} from "lucide-react";

export default function AlreadyAuthenticated() {
  // Optional: Handle logout directly from this page if they want to switch accounts
  const handleLogout = () => {
    localStorage.removeItem("accessToken");
    window.location.href = "/login";
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] flex items-center justify-center p-6">
      <div className="max-w-[480px] w-full bg-white rounded-[3rem] shadow-sm border border-slate-100 overflow-hidden">
        {/* Top Branding Bar */}
        <div className="bg-emerald-500 p-8 text-white relative overflow-hidden">
          <div className="absolute top-0 right-0 p-4 opacity-20">
            <Sparkles size={120} />
          </div>

          <div className="relative z-10 flex flex-col items-center">
            <div className="w-20 h-20 bg-white/20 backdrop-blur-xl rounded-[2rem] flex items-center justify-center border border-white/30 mb-4 shadow-2xl">
              <UserCheck size={40} className="text-white" />
            </div>
            <div className="inline-flex items-center gap-2 px-3 py-1 bg-white/20 rounded-full mb-2">
              <ShieldCheck size={12} />
              <span className="text-[10px] font-black uppercase tracking-[0.2em]">
                Active Session
              </span>
            </div>
            <h1 className="text-2xl font-black tracking-tight">
              You're already in!
            </h1>
          </div>
        </div>

        {/* Content Section */}
        <div className="p-10 text-center space-y-8">
          <div className="space-y-3">
            <h2 className="text-xl font-bold text-slate-800">
              No need to sign in again
            </h2>
            <p className="text-slate-500 font-medium leading-relaxed">
              You are currently logged into your account. To access the login or
              registration pages, you'll need to sign out first.
            </p>
          </div>

          <div className="space-y-3">
            {/* Primary Action: Go to App */}
            <Link
              href="/"
              className="w-full h-16 bg-emerald-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs flex items-center justify-center gap-3 transition-all hover:bg-slate-900 shadow-xl shadow-emerald-100 active:scale-95"
            >
              <LayoutDashboard size={18} />
              Go to Home Page
              <ArrowRight size={18} />
            </Link>

            {/* Secondary Action: Logout */}
            <button
              onClick={handleLogout}
              className="w-full h-16 bg-white border border-slate-200 text-rose-500 rounded-2xl font-black uppercase tracking-widest text-xs flex items-center justify-center gap-3 transition-all hover:bg-rose-50 hover:border-rose-100 active:scale-95"
            >
              <LogOut size={18} />
              Sign Out of Account
            </button>
          </div>

          {/* Bottom Info */}
          <div className="pt-4">
            <p className="text-[10px] font-black uppercase tracking-widest text-slate-300">
              Secured Session • {new Date().toLocaleDateString()}
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}
